import { useScrollReveal } from "@/hooks/use-scroll-reveal";
import productsDisplay from "@/assets/products-display.jpg";

const AboutSection = () => {
  const { ref, isVisible } = useScrollReveal(0.15);

  return (
    <section id="sobre" className="py-24 md:py-36 bg-rose-soft" ref={ref}>
      <div className="container mx-auto px-6 md:px-12">
        <div className="grid md:grid-cols-2 gap-12 lg:gap-20 items-center">
          <div
            className={`transition-all duration-700 ${
              isVisible ? "opacity-100 translate-x-0" : "opacity-0 -translate-x-6"
            }`}
            style={{ transitionTimingFunction: "cubic-bezier(0.16, 1, 0.3, 1)" }}
          >
            <div className="relative overflow-hidden rounded-sm">
              <img
                src={productsDisplay.src}
                alt="Nossa linha de produtos"
                className="w-full object-cover"
                loading="lazy"
              />
              <div className="absolute inset-0 ring-1 ring-inset ring-foreground/5 rounded-sm" />
            </div>
          </div>

          <div
            className={`transition-all duration-700 ${
              isVisible ? "opacity-100 translate-x-0" : "opacity-0 translate-x-6"
            }`}
            style={{
              transitionDelay: "150ms",
              transitionTimingFunction: "cubic-bezier(0.16, 1, 0.3, 1)",
            }}
          >
            <p className="font-sans text-sm tracking-[0.25em] uppercase text-gold mb-3">
              Sobre Nós
            </p>
            <h2 className="font-serif text-4xl md:text-5xl font-light text-foreground leading-[1.1] text-balance mb-6">
              Beleza que nasce do cuidado
            </h2>
            <p className="font-sans text-base text-muted-foreground leading-relaxed text-pretty mb-5">
              Nascemos da paixão por cabelos saudáveis e radiantes. Cada fórmula é desenvolvida
              com ingredientes naturais cuidadosamente selecionados, unindo ciência e tradição
              para entregar resultados visíveis desde a primeira aplicação.
            </p>
            <p className="font-sans text-base text-muted-foreground leading-relaxed text-pretty mb-8">
              Acreditamos que o autocuidado é um ritual — e seus cabelos merecem
              o que há de melhor.
            </p>

            <div className="flex gap-12">
              {[
                { number: "100%", label: "Vegano" },
                { number: "12+", label: "Produtos" },
                { number: "5mil+", label: "Clientes" },
              ].map((stat) => (
                <div key={stat.label}>
                  <p className="font-serif text-3xl font-semibold text-primary tabular-nums">
                    {stat.number}
                  </p>
                  <p className="font-sans text-xs tracking-wider uppercase text-muted-foreground mt-1">
                    {stat.label}
                  </p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default AboutSection;

"use client";

import { ShaderGradient } from "shadergradient";

export default function Background() {
  return (
    <div className="fixed inset-0 -z-10">
      <ShaderGradient
        {...({
          animate: "on",
          bgColor1: "#000000",
          bgColor2: "#000000",
          brightness: 1.5,
          color1: "#ff7a33",
          color2: "#33a0ff",
          color3: "#ffc53d",
          type: "sphere",
          uAmplitude: 1.4,
          uDensity: 1.1,
          uFrequency: 5.5,
          uSpeed: 0.1,
          uStrength: 0.4,
        } as any)}
      />
      {/* overlay pra dar contraste */}
      <div className="absolute inset-0 bg-black/40" />
    </div>
  );
}

import { useScrollReveal } from "@/hooks/use-scroll-reveal";
import productSerum from "@/assets/product-serum.jpg";
import productMask from "@/assets/product-mask.jpg";
import productShampoo from "@/assets/product-shampoo.jpg";

const products = [
  {
    name: "Sérum Reparador",
    description: "Óleo concentrado que sela as cutículas e devolve o brilho natural aos fios danificados.",
    price: "R$ 189,90",
    image: productSerum,
  },
  {
    name: "Máscara Nutritiva",
    description: "Hidratação profunda com manteiga de karité e proteínas vegetais para cabelos sedosos.",
    price: "R$ 149,90",
    image: productMask,
  },
  {
    name: "Shampoo Revitalizante",
    description: "Limpeza suave sem sulfatos, preservando a cor e a saúde natural dos seus cabelos.",
    price: "R$ 119,90",
    image: productShampoo,
  },
];

const ProductsSection = () => {
  const { ref, isVisible } = useScrollReveal(0.15);

  return (
    <section id="produtos" className="py-24 md:py-32 bg-background" ref={ref}>
      <div className="container mx-auto px-6 md:px-12">
        <div
          className={`text-center mb-16 transition-all duration-700 ${
            isVisible ? "opacity-100 translate-y-0" : "opacity-0 translate-y-4"
          }`}
          style={{ transitionTimingFunction: "cubic-bezier(0.16, 1, 0.3, 1)" }}
        >
          <p className="font-sans text-sm tracking-[0.25em] uppercase text-gold mb-3">
            Coleção
          </p>
          <h2 className="font-serif text-4xl md:text-5xl font-light text-foreground text-balance">
            Nossos Produtos
          </h2>
        </div>

        <div className="grid md:grid-cols-3 gap-8 lg:gap-12">
          {products.map((product, i) => (
            <div
              key={product.name}
              className={`group transition-all duration-700 ${
                isVisible ? "opacity-100 translate-y-0" : "opacity-0 translate-y-6"
              }`}
              style={{
                transitionDelay: `${(i + 1) * 120}ms`,
                transitionTimingFunction: "cubic-bezier(0.16, 1, 0.3, 1)",
              }}
            >
              <div className="relative overflow-hidden rounded-sm bg-card mb-5">
                <img
                  src={product.image.src}
                  alt={product.name}
                  className="w-full aspect-square object-cover transition-transform duration-500 group-hover:scale-105"
                  loading="lazy"
                />
                <div className="absolute inset-0 ring-1 ring-inset ring-foreground/5 rounded-sm" />
              </div>
              <div className="px-1">
                <h3 className="font-serif text-2xl font-medium text-foreground mb-2">
                  {product.name}
                </h3>
                <p className="font-sans text-sm text-muted-foreground leading-relaxed text-pretty mb-3">
                  {product.description}
                </p>
                <p className="font-sans text-base font-medium text-gold">
                  {product.price}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default ProductsSection;

